38	-------------------------------------------------------------------------------
39	   function getPrbs1xTap (input : slv; tap0 : natural) return slv is
40	      variable retVar : slv(input'left downto 0) := (others => '0');
41	   begin
42	
43	      --check for a valid tap location
44	      assert (tap0 <= input'left) report "PrbsPkg: getPrbs1xTap's tap0 input is out of range" severity failure;
45	
46	      -- shift register
47	      for i in (input'left - 1) downto 0 loop
48	         retVar(i) := input(i+1);
49	      end loop;
50	
51	      -- calculate the "xor'd" feedback
52	      retVar(input'left) := input(0) xor input(tap0);
53	
54	      --return the result
55	      return retVar;
