107	
108	   function getPrbs4xTap (input : slv; tap0, tap1, tap2, tap3 : natural) return slv is
109	      variable retVar : slv(input'left downto 0) := (others => '0');
110	   begin
111	
112	      --check for a valid tap location
113	      assert (tap0 <= input'left) report "PrbsPkg: getPrbs3xTap's tap0 input is out of range" severity failure;
114	      assert (tap1 <= input'left) report "PrbsPkg: getPrbs3xTap's tap1 input is out of range" severity failure;
115	      assert (tap2 <= input'left) report "PrbsPkg: getPrbs3xTap's tap2 input is out of range" severity failure;
116	      assert (tap3 <= input'left) report "PrbsPkg: getPrbs3xTap's tap3 input is out of range" severity failure;
117	
118	      -- shift register
119	      for i in (input'left - 1) downto 0 loop
120	         retVar(i) := input(i+1);
121	      end loop;
122	
123	      -- calculate the "xor'd" feedback
124	      retVar(input'left) := input(tap0) xor input(tap1) xor input(tap2) xor input(tap3);
125	
126	      --return the result
127	      return retVar;
